# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import SwiftUI
import UIKit

struct Promo: Equatable {
    let code: String
    let discount: Int
}

final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var currentPromo: Promo?
    @Published private(set) var appliedPromos: [Promo] = []

    private init() {}

    func handleUniversalLink(_ url: URL) -> Bool {
        guard isValidPromoURL(url) else { return false }
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else { return false }

        let code = queryItems.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let discountString = queryItems.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""

        guard !code.isEmpty,
              let discount = Int(discountString),
              (1...100).contains(discount) else {
            return false
        }

        let promo = Promo(code: code, discount: discount)
        applyPromoToUserAccount(promo)
        return true
    }

    private func isValidPromoURL(_ url: URL) -> Bool {
        guard let host = url.host?.lowercased() else { return false }
        let path = url.path.lowercased()
        let scheme = url.scheme?.lowercased()
        return (scheme == "https") && host == "myapp.com" && path == "/promo"
    }

    private func applyPromoToUserAccount(_ promo: Promo) {
        currentPromo = promo
        if !appliedPromos.contains(promo) {
            appliedPromos.append(promo)
        }
        UserAccountStore.shared.applyPromo(code: promo.code, discount: promo.discount)
    }
}

final class UserAccountStore: ObservableObject {
    static let shared = UserAccountStore()

    @Published private(set) var appliedPromoCode: String?
    @Published private(set) var appliedDiscount: Int?

    private init() {}

    func applyPromo(code: String, discount: Int) {
        appliedPromoCode = code
        appliedDiscount = discount
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        return PromoManager.shared.handleUniversalLink(url)
    }
}

@main
struct PromoUniversalLinksApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @StateObject private var promoManager = PromoManager.shared
    @StateObject private var userAccountStore = UserAccountStore.shared

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(promoManager)
                .environmentObject(userAccountStore)
                .onOpenURL { url in
                    _ = PromoManager.shared.handleUniversalLink(url)
                }
        }
    }
}

